2	import { renderHook, act } from "@testing-library/react";
3	import type { ReactNode } from "react";
4	import { SessionProvider, useSession } from "@/features/session/context";
5	
6	const STORAGE_KEY = "bayes-session";
7	
8	const wrapper = ({ children }: { children: ReactNode }) => (
9	  <SessionProvider>{children}</SessionProvider>
10	);
11	
12	beforeEach(() => {
13	  localStorage.clear();
14	  vi.restoreAllMocks();
15	});
16	
17	describe("useSession", () => {
18	  it("returns default session values", () => {
19	    const { result } = renderHook(() => useSession(), { wrapper });
20	    expect(result.current.session).toEqual({ accountId: "", agentId: "" });
21	  });
22	
23	  it("loads session from localStorage on mount", () => {
24	    localStorage.setItem(STORAGE_KEY, JSON.stringify({ accountId: "acc1", agentId: "ag1" }));
25	    const { result } = renderHook(() => useSession(), { wrapper });
26	    expect(result.current.session).toEqual({ accountId: "acc1", agentId: "ag1" });
27	  });
28	
29	  it("setAccountId updates state and persists to localStorage", () => {
30	    const { result } = renderHook(() => useSession(), { wrapper });
31	    act(() => result.current.setAccountId("acc2"));
32	    expect(result.current.session.accountId).toBe("acc2");
33	    expect(JSON.parse(localStorage.getItem(STORAGE_KEY)!).accountId).toBe("acc2");
34	  });
35	
36	  it("setAgentId updates state and persists to localStorage", () => {
